#include <bits/stdc++.h>
using namespace std;

int n, x[50005], y[50005];

int main() {
    cin >> n;
    for (int i = 0; i < n; i++) {
        cin >> x[i];
    }
    for (int i = 0; i < n; i++) {
        cin >> y[i];
    }
    sort(x, x + n);
    sort(y, y + n);
    long long ans = 0;
    for (int i = 0; i < n; i++) {
        ans += abs(x[i] - y[i]);
    }
    cout << ans;
    return 0;
}
